import{_ as s,o as i,c as t,ag as r}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse(`{"title":"Gestion de l'equipe","description":"","frontmatter":{},"headers":[],"relativePath":"fr/settings/team.md","filePath":"fr/settings/team.md"}`),a={name:"fr/settings/team.md"};function l(o,e,n,c,u,d){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="gestion-de-l-equipe" tabindex="-1">Gestion de l&#39;equipe <a class="header-anchor" href="#gestion-de-l-equipe" aria-label="Permalink to &quot;Gestion de l&#39;equipe&quot;">​</a></h1><p>Invitez des membres d&#39;equipe, attribuez des roles et controlez qui peut acceder a quoi dans votre espace de travail.</p><h2 id="inviter-des-membres-d-equipe" tabindex="-1">Inviter des membres d&#39;equipe <a class="header-anchor" href="#inviter-des-membres-d-equipe" aria-label="Permalink to &quot;Inviter des membres d&#39;equipe&quot;">​</a></h2><ol><li>Allez dans <strong>Parametres &gt; Equipe</strong> ou <strong>Entreprise &gt; Membres de l&#39;equipe</strong></li><li>Cliquez sur <strong>Inviter un membre</strong></li><li>Entrez l&#39;<strong>adresse e-mail</strong> de la personne</li><li>Choisissez un <strong>role</strong> (voir ci-dessous)</li><li>Cliquez sur <strong>Envoyer l&#39;invitation</strong></li></ol><p>L&#39;invite recoit un e-mail avec un lien pour rejoindre votre espace de travail. S&#39;il n&#39;a pas de compte MyCompanyDesk, il peut en creer un durant le processus.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Description</th></tr></thead><tbody><tr><td><strong>Administrateur</strong></td><td>Acces complet a tout, y compris la gestion de l&#39;equipe et de la facturation</td></tr><tr><td><strong>Membre</strong></td><td>Acces aux fonctionnalites assignees, ne peut pas gerer l&#39;equipe ni la facturation</td></tr><tr><td><strong>Comptable</strong></td><td>Acces en lecture seule avec des vues comptables specifiques</td></tr></tbody></table><h3 id="administrateur" tabindex="-1">Administrateur <a class="header-anchor" href="#administrateur" aria-label="Permalink to &quot;Administrateur&quot;">​</a></h3><p>Les administrateurs peuvent :</p><ul><li>Gerer les membres de l&#39;equipe (inviter, supprimer, changer les roles)</li><li>Acceder aux parametres de facturation et d&#39;abonnement</li><li>Configurer les parametres de l&#39;entreprise</li><li>Acceder a toutes les fonctionnalites</li></ul><h3 id="membre" tabindex="-1">Membre <a class="header-anchor" href="#membre" aria-label="Permalink to &quot;Membre&quot;">​</a></h3><p>Les membres ont acces aux fonctionnalites que vous leur attribuez. Configurez leurs permissions par fonctionnalite.</p><h3 id="comptable" tabindex="-1">Comptable <a class="header-anchor" href="#comptable" aria-label="Permalink to &quot;Comptable&quot;">​</a></h3><p>Un role special pour les comptables externes :</p><ul><li>Consulter les donnees financieres (factures, depenses, rapports)</li><li>Ne peut pas creer ni modifier d&#39;enregistrements (par defaut)</li><li>Ensemble de permissions specifique a des fins d&#39;audit</li></ul><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>Les permissions detaillees vous permettent de controler l&#39;acces par fonctionnalite :</p><h3 id="acces-aux-pages" tabindex="-1">Acces aux pages <a class="header-anchor" href="#acces-aux-pages" aria-label="Permalink to &quot;Acces aux pages&quot;">​</a></h3><p>Choisissez quelles sections chaque membre peut voir :</p><ul><li>Factures</li><li>Devis</li><li>Depenses</li><li>Clients</li><li>Projets</li><li>Contrats</li><li>Objets</li><li>Enregistrement du temps</li><li>Rapports</li><li>TVA</li><li>Parametres</li></ul><h3 id="permissions-de-modification" tabindex="-1">Permissions de modification <a class="header-anchor" href="#permissions-de-modification" aria-label="Permalink to &quot;Permissions de modification&quot;">​</a></h3><p>Pour chaque page accessible, choisissez si le membre peut :</p><ul><li><strong>Consultation seule</strong> -- Acces en lecture, pas de modifications</li><li><strong>Modification</strong> -- Acces complet en lecture/ecriture</li></ul><h2 id="contacts-comptables" tabindex="-1">Contacts comptables <a class="header-anchor" href="#contacts-comptables" aria-label="Permalink to &quot;Contacts comptables&quot;">​</a></h2><p>Gerez les relations avec vos comptables externes :</p><ol><li>Allez dans <strong>Parametres &gt; Equipe &gt; Comptables</strong></li><li>Cliquez sur <strong>Ajouter un comptable</strong></li><li>Entrez son nom et son e-mail</li><li>Cliquez sur <strong>Inviter</strong> pour envoyer l&#39;acces</li><li>Configurez ses permissions specifiques</li></ol><h3 id="gerer-l-acces-des-comptables" tabindex="-1">Gerer l&#39;acces des comptables <a class="header-anchor" href="#gerer-l-acces-des-comptables" aria-label="Permalink to &quot;Gerer l&#39;acces des comptables&quot;">​</a></h3><ul><li><strong>Inviter</strong> -- Envoyez ou renvoyez l&#39;invitation d&#39;acces</li><li><strong>Revoquer</strong> -- Supprimez l&#39;acces (peut etre restaure ulterieurement)</li><li><strong>Restaurer</strong> -- Reactiver un acces precedemment revoque</li><li><strong>Mettre a jour les permissions</strong> -- Modifiez ce qu&#39;ils peuvent voir</li></ul><h2 id="changer-d-espace-de-travail" tabindex="-1">Changer d&#39;espace de travail <a class="header-anchor" href="#changer-d-espace-de-travail" aria-label="Permalink to &quot;Changer d&#39;espace de travail&quot;">​</a></h2><p>Si vous etes membre de plusieurs espaces de travail (entreprises), basculez entre eux :</p><ol><li>Cliquez sur le menu de votre compte</li><li>Selectionnez <strong>Changer d&#39;espace de travail</strong></li><li>Choisissez l&#39;espace de travail</li></ol><p>Ou creez un <strong>nouvel espace de travail</strong> depuis le meme menu.</p><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Utilisez le role comptable pour votre teneur de livres -- il fournit exactement l&#39;acces necessaire</li><li>Definissez les permissions des membres de maniere reflechie -- tout le monde n&#39;a pas besoin d&#39;acceder a la facturation ou aux parametres de l&#39;equipe</li><li>Revisez periodiquement les acces de l&#39;equipe, surtout lorsque les membres changent de role</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>La gestion d&#39;equipe au-dela d&#39;un membre necessite le plan <strong>Pro</strong>. Un nombre illimite de membres est disponible avec le plan <strong>Business</strong>.</p></div>',35)])])}const h=s(a,[["render",l]]);export{m as __pageData,h as default};
